            let steps = 0; // Track steps
            for (let i = 0; i < n; i++) {
                for (let j = 0; j < n - i - 1; j++) {
                    steps++; // Increment for each comparison
                    yield { array: [...arr], highlights: [j, j+1] }; // Yield current state and highlight compared elements
                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]]; // Swap
                        steps++; // Increment for swap
                        yield { array: [...arr], highlights: [j, j+1] }; // Yield after swap
                    }
                }
            }
            yield { array: [...arr], highlights: [] }; // Final sorted array
            return steps; // Return total steps at the end
        }

        // Generator for Quick Sort (yields after each partition and swap)
        function* quickSort(arr, low = 0, high = arr.length - 1) {
            let steps = 0; // Track steps
            function* partition(arr, low, high) {
                let pivot = arr[high];
                let i = low - 1;
                for (let j = low; j < high; j++) {
                    steps++; // Increment for each comparison
                    yield { array: [...arr], highlights: [j, high] }; // Highlight pivot and current element
                    if (arr[j] < pivot) {
                        i++;
                        [arr[i], arr[j]] = [arr[j], arr[i]]; // Swap
                        steps++; // Increment for swap
                        yield { array: [...arr], highlights: [i, j] }; // Yield after swap
                    }
                }
                [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]]; // Swap pivot
                steps++; // Increment for final swap
                yield { array: [...arr], highlights: [i + 1, high] };
                return i + 1;
            }

            if (low < high) {
                let pi = yield* partition(arr, low, high); // Yield from partition
                yield* quickSort(arr, low, pi - 1); // Recurse left
                yield* quickSort(arr, pi + 1, high); // Recurse right
            }
            yield { array: [...arr], highlights: [] }; // Final state
            return steps; // Return total steps
        }

        // Generator for Merge Sort (yields after each merge step)
        function* mergeSort(arr) {
            let steps = 0; // Track steps
            function* merge(arr, l, m, r) {
                let n1 = m - l + 1;
                let n2 = r - m;
                let L = arr.slice(l, m + 1);
                let R = arr.slice(m + 1, r + 1);

                let i = 0, j = 0, k = l;
                while (i < n1 && j < n2) {
                    steps++; // Increment for each comparison
                    yield { array: [...arr], highlights: [l + i, m + 1 + j] }; // Highlight elements being compared
                    if (L[i] <= R[j]) {
                        arr[k] = L[i];
                        i++;
                    } else {
                        arr[k] = R[j];
                        j++;
                    }
                    steps++; // Increment for assignment
                    yield { array: [...arr], highlights: [k] }; // Yield after merge step
                    k++;
                }

                while (i < n1) {
                    arr[k] = L[i];
                    steps++;
                    yield { array: [...arr], highlights: [k] };
                    i++;
                    k++;
                }

                while (j < n2) {
                    arr[k] = R[j];
                    steps++;
                    yield { array: [...arr], highlights: [k] };
                    j++;
                    k++;
                }
            }

            function* sort(arr, l, r) {
                if (l < r) {
                    let m = Math.floor((l + r) / 2);
                    yield* sort(arr, l, m);
                    yield* sort(arr, m + 1, r);
                    yield* merge(arr, l, m, r);
                }
            }

            yield* sort(arr, 0, arr.length - 1);
            yield { array: [...arr], highlights: [] }; // Final sorted array
            return steps; // Return total steps
        }

        // Initialize and run the sorts
        const bubbleArray = [...originalArray];
        const quickArray = [...originalArray];
        const mergeArray = [...originalArray];

        const bubbleGen = bubbleSort(bubbleArray);
        const quickGen = quickSort(quickArray);
        const mergeGen = mergeSort(mergeArray);

        // Initial render
        renderBars('bubble-chart', bubbleArray);
        renderBars('quick-chart', quickArray);
        renderBars('merge-chart', mergeArray);

        // Animate the generators
        function animate(generator, chartId, stepsId) {
            let steps = 0;
            function nextStep() {
                const result = generator.next();
                if (!result.done) {
                    const { array, highlights } = result.value;
                    renderBars(chartId, array, highlights);
                    steps++;
                    document.getElementById(stepsId).textContent = steps;
                    setTimeout(nextStep, 100); // Delay for animation (100ms per step)
                } else {
                    renderBars(chartId, result.value.array, []); // Final render
                    document.getElementById(stepsId).textContent = steps + result.value; // Add final steps if returned
                }
            }
            nextStep();
        }

        // Start animations
        animate(bubbleGen, 'bubble-chart', 'bubble-steps');
        animate(quickGen, 'quick-chart', 'quick-steps');
        animate(mergeGen, 'merge-chart', 'merge-steps');
    </script>
</body>
