            document.getElementById(id).textContent = `Steps: ${steps}`;
        }

        // Bubble Sort implementation with steps and animation
        async function bubbleSort(array) {
            let steps = 0;
            let arr = array.slice(); // Copy array
            for (let i = 0; i < arr.length; i++) {
                for (let j = 0; j < arr.length - i - 1; j++) {
                    steps++; // Increment for comparison
                    updateSteps('bubble-steps', steps);
                    renderChart('bubble-chart', arr, [j, j+1]); // Highlight compared elements
                    await sleep(500); // Slow down for visibility
                    if (arr[j] > arr[j + 1]) {
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]]; // Swap
                        steps++; // Increment for swap
                        updateSteps('bubble-steps', steps);
                        renderChart('bubble-chart', arr, [j, j+1]); // Re-render with swap
                        await sleep(500); // Animate swap
                    }
                    renderChart('bubble-chart', arr); // Remove highlights
                    await sleep(100); // Brief pause
                }
            }
            updateSteps('bubble-steps', steps);
            return arr;
        }

        // Quick Sort implementation with steps and animation
        async function quickSort(arr, low = 0, high = null, stepsElemId) {
            if (high === null) high = arr.length - 1;
            let steps = parseInt(document.getElementById(stepsElemId).textContent.replace('Steps: ', '')); // Get current steps
            if (low < high) {
                let pivotIndex = await partition(arr, low, high, stepsElemId);
                steps += (high - low); // Approximate steps for partition
                await quickSort(arr, low, pivotIndex - 1, stepsElemId);
                await quickSort(arr, pivotIndex + 1, high, stepsElemId);
            }
            renderChart(stepsElemId.replace('-steps', '-chart'), arr); // Update chart
            updateSteps(stepsElemId, steps + (high - low)); // Final steps
            await sleep(200); // Brief animation pause
        }

        async function partition(arr, low, high, stepsElemId) {
            let pivot = arr[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                document.getElementById(stepsElemId).innerText = `Steps: ${parseInt(document.getElementById(stepsElemId).textContent.replace('Steps: ', '')) + 1}`;
                renderChart(stepsElemId.replace('-steps', '-chart'), arr, [j, high]); // Highlight
                await sleep(300);
                if (arr[j] < pivot) {
                    i++;
                    [arr[i], arr[j]] = [arr[j], arr[i]]; // Swap
                    renderChart(stepsElemId.replace('-steps', '-chart'), arr, [i, j]);
                    await sleep(300);
                }
            }
            [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
            renderChart(stepsElemId.replace('-steps', '-chart'), arr);
            await sleep(300);
            return i + 1;
        }

        // Merge Sort implementation with steps and animation
        async function mergeSort(arr, stepsElemId) {
            let steps = parseInt(document.getElementById(stepsElemId).textContent.replace('Steps: ', '')); // Get current steps
            if (arr.length > 1) {
                const mid = Math.floor(arr.length / 2);
                const left = arr.slice(0, mid);
                const right = arr.slice(mid);

                await mergeSort(left, stepsElemId); // Recursive call
                await mergeSort(right, stepsElemId);

                let i = 0, j = 0, k = 0;
                while (i < left.length && j < right.length) {
                    steps++; // Increment for comparison
                    updateSteps(stepsElemId, steps);
                    renderChart(stepsElemId.replace('-steps', '-chart'), arr); // Temp render
                    await sleep(400); // Slow for visibility
                    if (left[i] <= right[j]) {
                        arr[k] = left[i];
                        i++;
                    } else {
                        arr[k] = right[j];
                        j++;
                    }
                    k++;
                }

                while (i < left.length) {
                    arr[k] = left[i];
                    i++;
                    k++;
                    steps++;
                    updateSteps(stepsElemId, steps);
                    await sleep(400);
                }

                while (j < right.length) {
                    arr[k] = right[j];
                    j++;
                    k++;
                    steps++;
                    updateSteps(stepsElemId, steps);
                    await sleep(400);
                }

                renderChart(stepsElemId.replace('-steps', '-chart'), arr); // Final render
            }
            return arr;
        }

        // Sleep function for animations
        function sleep(ms) {
            return new Promise(resolve => setTimeout(resolve, ms));
        }

        // Initial render
        renderChart('bubble-chart', initialArray);
        renderChart('quick-chart', initialArray);
        renderChart('merge-chart', initialArray);

        // Start button event
        document.getElementById('start-button').addEventListener('click', async () => {
            // Reset steps
            updateSteps('bubble-steps', 0);
            updateSteps('quick-steps', 0);
            updateSteps('merge-steps', 0);

            // Start all sorts concurrently
            const bubblePromise = bubbleSort(initialArray);
            const quickPromise = quickSort(initialArray.slice(), 0, initialArray.length - 1, 'quick-steps');
            const mergePromise = mergeSort(initialArray.slice(), 'merge-steps');

            await Promise.all([bubblePromise, quickPromise, mergePromise]);
            alert('Sorting complete! Check the step counters for the performance gap.');
        });
    </script>
